package com.example.samlsp.config;

import org.opensaml.security.credential.Credential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.io.ResourceLoader;

import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

@Configuration
public class KeyStoreConfig {

    @Autowired
    private SamlProperties samlProperties;

    @Autowired
    private ResourceLoader resourceLoader;

    @Bean
    public Credential spCredential() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = resourceLoader.getResource(samlProperties.getKeystorePath()).getInputStream()) {
            keyStore.load(is, samlProperties.getKeystorePassword().toCharArray());
        }

        X509Certificate certificate = (X509Certificate) keyStore.getCertificate(samlProperties.getKeyAlias());
        PrivateKey privateKey = (PrivateKey) keyStore.getKey(
                samlProperties.getKeyAlias(),
                samlProperties.getKeyPassword().toCharArray()
        );

        BasicX509Credential credential = new BasicX509Credential(certificate, privateKey);
        credential.setEntityId(samlProperties.getEntityId());
        return credential;
    }

    @Bean
    public Credential idpCredential() throws Exception {
        if (samlProperties.getIdpCertificatePath() != null) {
            try (InputStream is = resourceLoader.getResource(samlProperties.getIdpCertificatePath()).getInputStream()) {
                java.security.cert.CertificateFactory cf = java.security.cert.CertificateFactory.getInstance("X.509");
                X509Certificate cert = (X509Certificate) cf.generateCertificate(is);
                return new BasicX509Credential(cert);
            }
        }
        return null;
    }
}

